module top_module(
  input clk_in,
  input reset,
  output reg clk_out
);parameter divide_by = 2;

reg [31:0] countdown;

always @(posedge clk_in or posedge reset) begin
  if (reset) begin
    clk_out <= 1'b0;
    countdown <= 0;
  end
  else begin
    if (countdown == divide_by - 1) begin
      clk_out <= ~clk_out;
      countdown <= 0;
    end
    else begin
      countdown <= countdown + 1;
    end
  end
end

endmodule
